def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        base_factor = np.tanh(ratio * 3) + 1.1
        complexity = 0.0
        modifier = 1.0
        penalty = 0.0
        bonus = 0.0
        history = []
        for a in range(1, 15):
            for b in range(1, 7):
                cmp_val = (cap + a*b) % (7 + b)
                if cmp_val == 0:
                    modifier *= (1 + 0.007 * a * b)
                elif cmp_val < b:
                    modifier /= (1 + 0.003 * a * b)
                if a % 2 == 0 and b % 3 == 0:
                    complexity += (a*b) / (1 + np.exp(-ratio * a))
                else:
                    complexity += np.log1p(a*b) / (b + 1) + (ratio**2) * 0.1
                hist_val = np.sin(ratio * a * b) * np.log1p(cap + item + a + b)
                history.append(hist_val)
            if a % 5 == 0:
                penalty += np.sqrt(abs(cap - item * a)) / (a + 3)
                if penalty > 5:
                    penalty *= 0.9
            if ratio > 0.9 and a % 4 == 0:
                bonus += np.exp(-a*ratio*0.1)
            elif ratio < 0.1 and a % 3 == 1:
                bonus -= (a ** 1.5) / (cap + 2)
        hist_sum = np.sum(history)
        total_score = (complexity * modifier + bonus - penalty) * base_factor + hist_sum * 0.05
        if total_score < 0:
            total_score = -total_score * (np.log1p(cap) + item/(cap+1))
        else:
            if cap < item * 2:
                total_score /= (cap + 1) ** 0.7
            else:
                total_score *= (1 + np.sin(ratio * 4))
        if cap % 3 == 0:
            total_score *= 0.95 + 0.03 * (i % 5)
        else:
            total_score *= 1.05 - 0.02 * (i % 4)
        if ratio > 1.2:
            total_score *= 1.25
        elif ratio < 0.15:
            total_score *= 0.7
        if i % 2 == 0:
            priorities[i] = -total_score
        else:
            priorities[i] = -total_score * 1.1
    return priorities
